app.use(bodyParser.json());

const CLIENT_ID = 'your_client_id';
const CLIENT_SECRET = 'your_client_secret';
const JWT_SECRET = 'your_jwt_secret';
const REFRESH_TOKEN_EXPIRY = 365 * 24 * 60 * 60; // 1 year in seconds

redisClient.on('error', (err) => {
    console.error('Redis error:', err);
});

app.post('/token', (req, res) => {
    const { client_id, client_secret, grant_type } = req.body;

    if (client_id !== CLIENT_ID || client_secret !== CLIENT_SECRET || grant_type !== 'refresh_token') {
        return res.status(400).json({ error: 'invalid_client' });
    }

    const refreshToken = req.body.refresh_token;
    redisClient.get(refreshToken, (err, tokenData) => {
        if (err || !tokenData) {
            return res.status(400).json({ error: 'invalid_grant' });
        }

        const userData = JSON.parse(tokenData);
        const newAccessToken = jwt.sign({ userId: userData.userId }, JWT_SECRET, { expiresIn: '1h' });

        res.json({
            access_token: newAccessToken,
            refresh_token: refreshToken,
            token_type: 'Bearer',
            expires_in: 3600
        });
    });
});

